% THEORY
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
\section{Near-Reference Drift-Budgeted SFT: Theory}
\label{sec:nearref_lst_theory}
We study a regime of \emph{near-reference drift-budgeted supervised fine-tuning (SFT)}: we aim to improve a supervised objective while explicitly limiting \emph{function-space} drift from a strong reference checkpoint $\theta_0$.
Let $\pi_\theta(\cdot|x)$ denote the model distribution over outputs given input $x$.
Given an SFT dataset $\mathcal D$, we define the task loss
\begin{equation}
\mathcal{T}(\theta)
\ :=\
\mathbb{E}_{(x,y^*)\sim\mathcal{D}}[-\log \pi_{\theta}(y^*|x)].
\label{eq:tsft_def}
\end{equation}
We measure functional drift from $\theta_0$ by the expected KL divergence
\begin{equation}
D_{\mathrm{ref}}(\theta)
\ :=\
\mathbb{E}_{x\sim\mu}\Big[\mathrm{KL}\big(\pi_{\theta}(\cdot|x)\ \|\ \pi_{\theta_0}(\cdot|x)\big)\Big],
\label{eq:dref_def}
\end{equation}
where $\mu$ is a fixed input distribution (in practice approximated by a probe set; see \S\ref{subsec:drift_diagnostics}).
Our target problem is the drift-budgeted optimization
\begin{equation}
\min_{\theta\in\Theta}\ \mathcal{T}(\theta)
\qquad \text{s.t.}\qquad
D_{\mathrm{ref}}(\theta)\le \delta,
\label{eq:drift_budget_problem}
\end{equation}
where $\Theta$ denotes an \emph{update class} (the feasible set of parameter updates).
We focus on \emph{coordinate restriction} update classes because they preserve the original parameterization and yield a direct local geometry under KL drift.
In particular, we study \emph{layer-selective tuning (LST)}, which restricts updates to a subset of transformer blocks $M$ and freezes the rest:
\begin{equation}
\theta_{\neg M}\ \equiv\ \theta_{0,\neg M}.
\label{eq:lst_constraint}
\end{equation}
This restriction yields a family of feasible sets indexed by $M$; our method will later select $M$ by comparing candidates at \emph{matched drift}.
\subsection{Local drift geometry and drift-normalized improvement}
\label{subsec:lst_local_geometry}
In a sufficiently small neighborhood of $\theta_0$, KL drift induces a Fisher quadratic form.
Let $F$ be the Fisher information matrix of $\pi_{\theta_0}$ under the same input distribution $\mu$ as in Eq.~\eqref{eq:dref_def}.
\begin{lemma}[Local quadratic approximation of KL drift]
\label{lem:kl_fisher}
For $\theta=\theta_0+\Delta\theta$ in a sufficiently small neighborhood of $\theta_0$,
\begin{equation}
D_{\mathrm{ref}}(\theta_0+\Delta\theta)
\ \approx\
\frac{1}{2}\Delta\theta^\top F\,\Delta\theta.
\label{eq:kl_fisher_quadratic}
\end{equation}
Under LST ($\Delta\theta_{\neg M}=0$),
\begin{equation}
D_{\mathrm{ref}}(\theta_0+\Delta\theta_M)
\ \approx\
\frac{1}{2}\Delta\theta_M^\top F_M\,\Delta\theta_M,
\label{eq:kl_fisher_quadratic_restricted}
\end{equation}
where $F_M:=F_{MM}$ is the principal submatrix on coordinates in $M$.
\end{lemma}
Lemma~\ref{lem:kl_fisher} turns the drift budget $D_{\mathrm{ref}}(\theta)\le\delta$ into an (approximate) ellipsoidal constraint in the trainable coordinates.
Let $g := \nabla \mathcal{T}(\theta)\vert_{\theta_0}$ and $g_M$ its restriction to $M$.
\begin{lemma}[Best first-order SFT improvement within LST at a fixed drift budget]
\label{lem:budgeted_improvement}
Assume $F_M\succ 0$. Consider the local drift-budgeted subproblem within the LST subspace:
\begin{equation}
\min_{\Delta\theta_M}\ g_M^\top \Delta\theta_M
\quad \text{s.t.}\quad
\frac{1}{2}\Delta\theta_M^\top F_M\Delta\theta_M\le \delta.
\label{eq:local_trust_region_lst}
\end{equation}
Its optimal value is
\begin{equation}
\min \eqref{eq:local_trust_region_lst}
\ =\
-\sqrt{2\delta}\,\|g_M\|_{F_M^{-1}},
\qquad
\|\upsilon\|_{F_M^{-1}}^2 := \upsilon^\top F_M^{-1}\upsilon,
\label{eq:local_improvement_value}
\end{equation}
achieved by $\Delta\theta_M \propto -F_M^{-1}g_M$.
\end{lemma}
\paragraph{Practical note (damping).}
In large models, $F_M$ can be singular or ill-conditioned.
In practice we use a damped metric $(F_M+\lambda I)$ and replace $F_M^{-1}$ by $(F_M+\lambda I)^{-1}$ (or a pseudoinverse).
Lemma~\ref{lem:budgeted_improvement} implies that, in the near-reference regime, the \emph{subset-dependent potential} for improvement under a fixed drift budget is governed by the drift-normalized signal $\|g_M\|_{(F_M+\lambda I)^{-1}}$.
\subsection{Decomposing performance limits: subset capacity vs.\ optimization error}
\label{subsec:restriction_vs_optimization}
Under a fixed drift budget, LST performance is limited by two conceptually distinct factors.
\paragraph{(i) Subset capacity (restriction gap).}
Even with an ideal solver, restricting updates to $M$ limits which drift-efficient descent directions are reachable.
Lemma~\ref{lem:budgeted_improvement} quantifies this limitation in the near-reference regime: if $M$ does not capture drift-efficient components of the gradient, then $\|g_M\|_{F_M^{-1}}$ will be small, and no procedure confined to $M$ can achieve large improvement at small drift.
This motivates \emph{selecting} $M$ by comparing candidates at matched drift.
\paragraph{(ii) Optimization error (attainability within a subset).}
Fix a subset $M$. Define the oracle best achievable value within LST under budget $\delta$:
\begin{equation}
\mathcal{T}^{\star}_{\mathrm{LST}}(\delta;M)
:=
\min_{\theta}\ \mathcal{T}(\theta)
\quad \text{s.t.}\quad
D_{\mathrm{ref}}(\theta)\le \delta,\ \theta_{\neg M}=\theta_{0,\neg M}.
\label{eq:lst_oracle_opt}
\end{equation}
For any trained checkpoint $\hat\theta(M)$ satisfying $D_{\mathrm{ref}}(\hat\theta(M))\le \delta$, the restricted optimization error is
\begin{equation}
\mathrm{OptErr}_{\mathrm{LST}}(\hat\theta(M);\delta)
:=
\mathcal{T}(\hat\theta(M))-\mathcal{T}^{\star}_{\mathrm{LST}}(\delta;M)\ \ge 0.
\label{eq:opterr_lst}
\end{equation}
This isolates solver-dependent limitations: how close training gets to the subset-dependent oracle within the same drift budget.
\paragraph{Preview of the method.}
Our method addresses these two limitations separately:
(1) we choose $M$ via \emph{matched-drift subset selection}, a black-box proxy for drift-normalized improvement; and
(2) once $M$ is fixed, we reduce $\mathrm{OptErr}_{\mathrm{LST}}$ using a two-stage schedule designed to absorb cross-segment coupling.
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% METHOD
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
\section{Method: Anchored-LST and Matched-Drift Subset Selection}
\label{sec:method_anchored_lst}
Based on the theoretical framework in \S\ref{sec:nearref_lst_theory}, we propose a practical adaptation protocol for drift-budgeted LST.
The organizing principle is:
\begin{quote}
\emph{A subset $M$ is preferred if it yields larger evaluation improvement at the same measured drift from the reference.}
\end{quote}
To make ``same drift'' comparable across different $M$, we (i) fix endpoint degrees of freedom (Anchored-LST), (ii) define a stable probe-based drift diagnostic, and (iii) score candidates by early-stopped improvement at a matched drift budget.
Finally, we use a two-stage solver to reduce restricted optimization error for structured (two-segment) subsets.
\subsection{Anchored-LST: fixing endpoint gauge freedoms}
\label{subsec:anchored_lst}
Matched-drift comparison across different trainable subsets requires drift to be measured in a \emph{fixed} coordinate system.
If the input embedding or the output projection (LM head) is trainable, endpoint gauge freedoms can obscure drift comparability and increase solver-dependent variability.
\paragraph{Output gauge freedom.}
For a decoder LM with hidden states $h_\theta(x,t)$ and output head $(W_{\mathrm{out}},b_{\mathrm{out}})$, training $W_{\mathrm{out}}$
admits near-invariant transformations
\begin{equation}
h_\theta(x,t)\ \mapsto\ h_\theta(x,t)A,
\qquad
W_{\mathrm{out}}\ \mapsto\ W_{\mathrm{out}}A^{-T},
\label{eq:output_gauge}
\end{equation}
for invertible $A$, which can preserve logits while inducing large parameter motion and poor conditioning.
Similarly, training the input embedding can change the representation basis at the input and be compensated downstream.
\paragraph{Anchored-LST (default).}
We therefore freeze both the input embedding and the output projection (LM head), and select trainable coordinates only from transformer blocks.
This \emph{anchors} the lexical input basis and the readout basis, ensuring that drift measurements primarily reflect backbone-induced functional change and remain comparable across different subsets $M$.
\subsection{Practical drift diagnostics}
\label{subsec:drift_diagnostics}
With endpoints fixed, we measure drift in a fixed readout basis using the frozen reference head.
Let $h_\theta(x,t)$ be the final-layer hidden state under teacher forcing at token position $t$, and let $(W_0,b_0)$ be the frozen output head from $\theta_0$.
Define the reference-head distribution
\begin{equation}
p^0_\theta(\cdot|x,t)
=\mathrm{softmax}\!\left(h_\theta(x,t)W_0^\top+b_0\right).
\label{eq:p_ref_head}
\end{equation}
We estimate drift on a probe set $\mathcal{X}_{\mathrm{probe}}$ (approximating $x\sim\mu$ in Eq.~\eqref{eq:dref_def}) via
\begin{equation}
\widehat D_{\mathrm{ref}}(\theta)
:=
\mathbb{E}_{x\in\mathcal{X}_{\mathrm{probe}},\,t}
\Big[
\mathrm{KL}\big(p^0_\theta(\cdot|x,t)\ \|\ p^0_{\theta_0}(\cdot|x,t)\big)
\Big].
\label{eq:D_ref_probe}
\end{equation}
Because the same frozen head is used for all candidates, $\widehat D_{\mathrm{ref}}$ provides a directly comparable drift axis across subsets $M$.
\subsection{Matched-drift subset selection}
\label{subsec:subset_selection}
Lemma~\ref{lem:budgeted_improvement} suggests that, in the near-reference regime, the best attainable first-order improvement within subset $M$ under drift budget $\delta$ scales with a drift-normalized quantity $\|g_M\|_{F_M^{-1}}$.
Computing $F_M^{-1}$ (or its action) explicitly is expensive at scale, so we use a black-box, solver-based proxy:
\emph{compare candidates by the improvement they realize when early-stopped at the same measured drift.}
Let $\mathcal{M}$ be a candidate family of trainable subsets.
For each $M\in\mathcal{M}$, we run a short tuning trajectory $\{\theta^{(k)}(M)\}_{k\ge 0}$ from $\theta^{(0)}(M)=\theta_0$ where only parameters in $M$ are trainable (Anchored-LST).
We stop when the measured drift reaches a preset budget $\delta$:
\begin{equation}
\tau(M)
\ :=\
\min\Big\{k\ge 0:\ \widehat D_{\mathrm{ref}}\big(\theta^{(k)}(M)\big)\ \ge\ \delta\Big\}.
\label{eq:stopping_time_tau}
\end{equation}
We then score $M$ by its improvement on a held-out evaluation metric $\mathcal{E}(\theta)$ (lower is better) at matched drift:
\begin{equation}
\mathrm{Score}(M;\delta)
\ :=\
\mathcal{E}(\theta_0)\ -\ \mathcal{E}\big(\theta^{(\tau(M))}(M)\big).
\label{eq:score_matched_drift}
\end{equation}
\paragraph{Interpretation.}
In the near-reference regime, Eq.~\eqref{eq:score_matched_drift} is motivated by Lemma~\ref{lem:budgeted_improvement}: when two candidates are compared at the same drift budget, the one that achieves larger improvement empirically corresponds to a larger drift-normalized descent signal.
We emphasize that this is a practical proxy (rather than an exact equality), since the observed trajectory depends on the optimizer, step size, and nonlinearity.
\paragraph{Structured candidate family (two segments).}
We consider the two-segment family
$M(x,y)=\{1,\dots,x\}\cup\{y,\dots,L\}$ (bottom block + top block).
This family contains $O(L^2)$ candidates.
To reduce search cost, we use a coarse-to-fine strategy: we first scan a coarse grid of endpoints $(x,y)$ with stride $s$ to identify promising regions under Eq.~\eqref{eq:score_matched_drift}, and then refine locally with smaller strides.
\subsection{Two-stage solver for coupled segments}
\label{subsec:two_stage_method}
Matched-drift selection chooses the feasible set (subset) $M$ and therefore targets the \emph{subset capacity} term.
Once $M$ is fixed, we aim to reduce the \emph{restricted optimization error} in Eq.~\eqref{eq:opterr_lst} under practical training, without changing the oracle optimum.
To model solver behavior beyond the first-order term, we use a local quadratic proxy on $M$:
\begin{equation}
\Phi(\Delta\theta_M)
:=
g_M^\top \Delta\theta_M
+\frac12 \Delta\theta_M^\top \Big(H_M+\beta(F_M+\lambda I)\Big)\Delta\theta_M,
\label{eq:phi_def_method}
\end{equation}
where $H_M$ is a local curvature matrix on $M$, $\beta>0$ sets the drift scale, and $\lambda\ge 0$ is a damping term.
Let $M=M_{\mathrm{low}}\cup M_{\mathrm{high}}$ (two contiguous segments) and partition $\Delta\theta_M=(\Delta\theta_L,\Delta\theta_H)$.
Write the proxy Hessian as
\begin{equation}
H_M+\beta(F_M+\lambda I)=
\begin{psmallmatrix}
A & C\\
C^\top & B
\end{psmallmatrix}.
\label{eq:block_hessian_def}
\end{equation}
\begin{proposition}[Coupling-induced correction captured by the second stage]
\label{prop:two_stage_correction}
Assume $A\succ 0$ and $B\succ 0$.
Let $\Delta_L^{\ast}:=\arg\min_{\Delta\theta_L}\Phi(\Delta\theta_L,0)$.
Fixing $\Delta\theta_L=\Delta_L^{\ast}$, the stage-2 conditional minimizer over the upper segment is
\begin{equation}
\Delta_H^{\ast}
\ =\
-B^{-1}\big(g_H + C^\top \Delta_L^{\ast}\big),
\label{eq:deltaH_star}
\end{equation}
where $g_H$ is the restriction of $g_M$ to the upper segment.
Decomposing,
\begin{equation}
\Delta_H^{\ast}
\ =\
\underbrace{-B^{-1}g_H}_{\text{direct upper-segment update}}
\ +\
\underbrace{\Delta_H^{\mathrm{corr}}}_{\text{coupling-induced correction}},
\qquad
\Delta_H^{\mathrm{corr}}:=-B^{-1}C^\top \Delta_L^{\ast}.
\label{eq:deltaH_decomp_method}
\end{equation}
The objective decrease attributable specifically to the coupling-induced correction (relative to taking only $-B^{-1}g_H$ in stage 2) is
\begin{equation}
\Phi(\Delta_L^{\ast},-B^{-1}g_H)\ -\ \Phi(\Delta_L^{\ast},\Delta_H^{\ast})
\ =\
\frac12\big\|B^{-1/2}C^\top \Delta_L^{\ast}\big\|_2^2.
\label{eq:two_stage_gain}
\end{equation}
\end{proposition}
Proposition~\ref{prop:two_stage_correction} does not claim two-stage improves the oracle optimum relative to joint optimization.
Instead, it isolates the coupling-induced correction term $\Delta_H^{\mathrm{corr}}$ that becomes necessary once the lower segment has moved, motivating staged optimization as a practical solver choice that can improve attainability (reduce $\mathrm{OptErr}_{\mathrm{LST}}$) under finite compute, noise, and nonconvexity.
\subsection{Computational complexity (time cost)}
\label{subsec:complexity}
We summarize the dominant time costs relative to full fine-tuning.
Let $L$ be the number of transformer blocks, and let $C_{\mathrm{step}}$ denote the wall-clock cost of one training step (forward+backward) for the base model.
Let $r(M)\in(0,1]$ denote the relative per-step cost when only subset $M$ is trainable (in practice close to 1 for backward through activations, but reduced optimizer/gradient update cost; we keep it explicit).
\paragraph{Matched-drift search cost.}
Let $|\mathcal M|$ be the number of candidate subsets evaluated, and let $K_\delta(M)$ be the number of steps needed for candidate $M$ to reach drift budget $\delta$ (the stopping time $\tau(M)$).
The total search cost is
\begin{equation}
\mathrm{Cost}_{\mathrm{search}}
\ \approx\
\sum_{M\in\mathcal M} K_\delta(M)\, r(M)\, C_{\mathrm{step}}
\ +\
\sum_{M\in\mathcal M} K_\delta(M)\, C_{\mathrm{drift}},
\label{eq:cost_search}
\end{equation}
where $C_{\mathrm{drift}}$ is the incremental cost of computing $\widehat D_{\mathrm{ref}}$ on $\mathcal X_{\mathrm{probe}}$.
If drift is computed every $q$ steps (rather than every step), the second term is reduced by a factor $\approx 1/q$.
\paragraph{Cost of drift evaluation.}
Computing $\widehat D_{\mathrm{ref}}(\theta)$ requires a forward pass on the probe set with teacher forcing to obtain token-level distributions $p_\theta^0(\cdot|x,t)$.
Let $|\mathcal X_{\mathrm{probe}}|$ be the number of probe sequences and $\bar T$ their average length.
Then
\begin{equation}
C_{\mathrm{drift}}
\ =\
O\!\left(|\mathcal X_{\mathrm{probe}}|\cdot \bar T \cdot C_{\mathrm{fwd/token}}\right),
\label{eq:cost_drift}
\end{equation}
where $C_{\mathrm{fwd/token}}$ is the per-token forward cost.
\paragraph{Two-segment coarse-to-fine search.}
For the two-segment family $M(x,y)$, the full candidate count is $O(L^2)$.
With a coarse stride $s$, the coarse scan evaluates $O((L/s)^2)$ candidates, and refinement typically evaluates an additional $O(R)$ candidates in a local neighborhood (small constant $R$).
Thus
\begin{equation}
|\mathcal M|
\ \approx\
O\!\left((L/s)^2 + R\right),
\label{eq:num_candidates}
\end{equation}
and the search cost scales accordingly.
In typical settings (e.g., $L{=}96$, $s\in\{8,16\}$), $(L/s)^2$ is on the order of $36$ to $144$ candidates, making matched-drift screening feasible with short warmup trajectories.
\paragraph{Final training cost.}
After selecting $M$, we run the main training (one-stage or two-stage).
If stage 1 uses $K_1$ steps on $M_{\mathrm{low}}$ and stage 2 uses $K_2$ steps on $M_{\mathrm{high}}$ (or on both segments with constraints), then
\begin{equation}
\mathrm{Cost}_{\mathrm{train}}
\ \approx\
(K_1+K_2)\, r(M)\, C_{\mathrm{step}}
\ +\
\frac{K_1+K_2}{q}\, C_{\mathrm{drift}}
\label{eq:cost_train}
\end{equation}
when drift is monitored every $q$ steps.
This is comparable to a standard LST run of $(K_1+K_2)$ steps, plus modest overhead for periodic drift evaluation.
\paragraph{Takeaway.}
The method adds an up-front screening phase whose cost is linear in the number of evaluated candidates and in the (typically small) number of warmup steps needed to reach the drift budget.
Coarse-to-fine search and infrequent drift evaluation ($q\gg 1$) make the overhead practical.
